sections.code:
for (int i = 1; i <= 5; i++) {
    if (i == 3) {
        continue;
    }
    System.out.println(i);
}

int[] numbers = {1, 2, 3, 4, 5, 6, 7, 8};
int sumOfEvens = 0;

for (int num : numbers) {
    if (num % 2 != 0) {
        continue;
    }
    sumOfEvens += num;
}

System.out.println("Sum of evens: " + sumOfEvens);

int i = 0;

while (i < 5) {
    i++;
    if (i == 3) {
        continue;
    }
    System.out.println(i);
}
// 1 2 4 5

public class Main {
    public static void main(String[] args) {
        int count = 0;

        for (int i = 1; i <= 20; i++) {
            if (i % 3 != 0) {
                continue;
            }
            count++;
        }

        System.out.println("Multiples of 3 from 1 to 20: " + count);
    }
}

